import React from 'react';

const Bio = () => {
  return (
    <section className="bg-[#0F172A] py-16 text-white"> 
      <div className="container mx-auto px-6 flex flex-col md:flex-row items-center gap-10">
        
        {/* Foto de Maribel */}
        <div className="w-full md:w-1/3 flex justify-center">
          <div className="w-64 h-80 rounded-2xl overflow-hidden shadow-2xl border-4 border-[#1e293b]">
            <img 
              src="/assets/maribel-perfil.jpg" 
              alt="Maribel Ferradas" 
              className="w-full h-full object-cover"
              onError={(e) => { e.target.src = "https://via.placeholder.com/400x500?text=Maribel"; }}
            />
          </div>
        </div>

        {/* Contenido de la Bio */}
        <div className="w-full md:w-2/3">
          <h2 className="text-3xl font-bold mb-4 text-blue-400">Sobre Mí</h2>
          <p className="text-lg leading-relaxed text-slate-200 mb-6">
            [AQUÍ VA TU TEXTO: Escribe aquí la descripción de tu trayectoria y pasión por el rubro inmobiliario]
          </p>
          <div className="inline-block border-l-2 border-blue-500 pl-4">
            <p className="text-sm uppercase tracking-widest text-slate-400 font-semibold">Registro MVCS</p>
            <p className="text-lg font-bold text-white">PN-XXXX-MVCS</p>
          </div>
        </div>

      </div>
    </section>
  );
};

export default Bio;
